package samples.guice.org.apache.shiro.samples.guice;

public class SampleShiroServletModule extends ShiroWebModule { private final ServletContext servletContext ; public SampleShiroServletModule ( ServletContext servletContext ) { super ( servletContext ) ; this . servletContext = servletContext ; } @ Override protected void configureShiroWeb ( ) { bindConstant ( ) . annotatedWith ( Names . named ( "shiro.loginUrl" ) ) . to ( "/login.jsp" ) ; try { this . bindRealm ( ) . toConstructor ( IniRealm . class . getConstructor ( Ini . class ) ) ; } catch ( NoSuchMethodException e ) { addError ( "Could not locate proper constructor for IniRealm." , e ) ; } this . addFilterChain ( "/login.jsp" , AUTHC ) ; this . addFilterChain ( "/logout" , LOGOUT ) ; this . addFilterChain ( "/account/**" , AUTHC ) ; this . addFilterChain ( "/remoting/**" , filterConfig ( AUTHC ) , filterConfig ( ROLES , "b2bClient" ) , filterConfig ( PERMS , "remote:invoke:lan,wan" ) ) ; } @ Provides @ Singleton Ini loadShiroIni ( ) throws MalformedURLException { URL iniUrl = servletContext . getResource ( "/WEB-INF/shiro.ini" ) ; return Ini . fromResourcePath ( "url:" + iniUrl . toExternalForm ( ) ) ; } @ Override protected void bindWebSecurityManager ( AnnotatedBindingBuilder < ? super WebSecurityManager > bind ) { try { String cipherKey = loadShiroIni ( ) . getSectionProperty ( "main" , "securityManager.rememberMeManager.cipherKey" ) ; DefaultWebSecurityManager securityManager = new DefaultWebSecurityManager ( ) ; CookieRememberMeManager rememberMeManager = new CookieRememberMeManager ( ) ; rememberMeManager . setCipherKey ( Base64 . decode ( cipherKey ) ) ; securityManager . setRememberMeManager ( rememberMeManager ) ; bind . toInstance ( securityManager ) ; } catch ( MalformedURLException e ) { throw new ConfigurationException ( "securityManager.rememberMeManager.cipherKey must be set in shiro.ini." ) ; } } }